+        assert_eq!(engine.cursor().col, 2);
+
+        engine.feed_bytes(b"\x08");
+        assert_eq!(engine.cursor().col, 1);
+
+        engine.feed_bytes(b"B");
+        let cell = engine.grid().cell(0, 1).expect("cell exists");
+        assert_eq!(cell.content(), 'B');
+        assert!(!cell.has_combining());
+    }
